#graphql
  query B2BContactMissingEmailCompaniesSearch($companyQuery: String!) {
    companies(first: 5, query: $companyQuery) {
      nodes {
        id
        name
        externalId
      }
      pageInfo {
        hasNextPage
        hasPreviousPage
      }
    }
  }

